-- 更新所有开课实例平均分
UPDATE course_instance ci SET ci.avg_score = (SELECT COALESCE(AVG(overall_score),0) FROM review r WHERE r.course_instance_id = ci.id AND r.status IN ('PUBLISHED','APPROVED')), ci.grading_score = (SELECT COALESCE(AVG(grading_score),0) FROM review r WHERE r.course_instance_id = ci.id AND r.status IN ('PUBLISHED','APPROVED')), ci.avg_teaching_score = (SELECT COALESCE(AVG(teaching_score),0) FROM review r WHERE r.course_instance_id = ci.id AND r.status IN ('PUBLISHED','APPROVED')), ci.avg_workload_score = (SELECT COALESCE(AVG(workload_score),0) FROM review r WHERE r.course_instance_id = ci.id AND r.status IN ('PUBLISHED','APPROVED')), ci.review_count = (SELECT COUNT(*) FROM review r WHERE r.course_instance_id = ci.id AND r.status IN ('PUBLISHED','APPROVED'));

-- 更新所有教师平均分
UPDATE teacher t SET t.avg_score = (SELECT COALESCE(AVG(overall_score),0) FROM review r WHERE r.teacher_id = t.id AND r.status IN ('PUBLISHED','APPROVED')), t.avg_teaching_score = (SELECT COALESCE(AVG(teaching_score),0) FROM review r WHERE r.teacher_id = t.id AND r.status IN ('PUBLISHED','APPROVED')), t.avg_workload_score = (SELECT COALESCE(AVG(workload_score),0) FROM review r WHERE r.teacher_id = t.id AND r.status IN ('PUBLISHED','APPROVED'));

