INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 1, 3, 2, 1, '警告/敬告：大四了还闭卷考试，不知道在讲什么，财务管理、管理会计、审计等课程完全可以平替（学分相同/授课内容雷同），别他妈选这个老师的这门课（我也是被迫抽到了很惨）。给平时分低，并且要求很多，大四了还以不能及格说事，。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '财务报告分析' AND t.teacher_name = '门瑢';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '敬告：授课质量非常高，可以说邢颖老师的课会计系第一。你想听懂财务管理的知识就选她的课，这门课不可能水过去（会计/财务管理专业的同学你们知道的，马忠是课题组长，作业量就这么大），所以想学明白就听邢颖老师的财务管理。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '财务管理' AND t.teacher_name = '邢颖';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '两个小组大作业+一个需要小组pre的案例分析，有一点点忙，上课不点名不签到，偶尔叫前排同学回答问题', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '财务管理理论与实务' AND t.teacher_name = '何琳';
