INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '先讲知识点，再讲例题，会点一两个人回答问题。上课体验良好', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '程序设计' AND t.teacher_name = '马迪芳';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 5, 5, '平时成绩占70%，作业难度不是很大，只要认真完成，基本上每次作业都可以得到高分。老师很温柔和善，讲课讲的也很好。期末是闭卷笔试，成绩占30%，难度也不是很大，平时作业认真完成很容易拿高分', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '程序设计分组训练' AND t.teacher_name = '田媚';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 2, 3, 3, 2, '老师人很好，很和蔼，非常平易近人，但是平时作业是真的难（对于没有基础的同学来说简直是噩梦的程度），不适合没有基础的同学呜呜，适合有一定扎实基础的同学', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '程序设计基础' AND t.teacher_name = '陈旭东';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '老师讲的会比较快，需要上课认真听讲，但是用心的话都可以听懂，课后作业也不多，有时候上课时间就可以写完，期末考试的难度也不是很大，都是选择与填空题，挺好过的，而且差个三四分的话老师也会捞一捞你。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '程序设计基础' AND t.teacher_name = '马迪芳';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '老师讲的很好很详细认真，学不会是我的问题', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '程序设计基础' AND t.teacher_name = '赵宏';
