INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 2, '上课一般就是PPT上的内容，会有一次平时作业，有两个pre，平时一次，期末一次，闭卷考，考试什么情况还不清楚，偶尔会点名，一学期三四次的样子吧', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '传播学概论' AND t.teacher_name = 'DYY';
