INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '老师很好，很温柔，下课早还会放一些很可爱的德语歌', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '德语口语入门' AND t.teacher_name = '于秀伟';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '于老师人特好，上课也特认真，有事请假老师也都特好说话。会点名回答问题，频率大概是两到三节课一次，但是都很简单，上课稍微留神听一点就OK，德语语音也不像语法那么难，很简单的听读。会带着一起读德语文，比如父与子。期末就是简单的听读考试，都是平时课上出现过的，一个人两三分钟就考完很快。给分很高！', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '德语语音入门' AND t.teacher_name = '于秀伟';
