INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '张金宝的课几乎不点名，作业查的比较松，而且答案都会发给大家。研究性实验也很水，几乎写了就给分，作业也都能补交不扣分。最重要的是狠狠捞人，不会让你挂，几乎都比自己预期分数要高很多。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '电磁场与电磁兼容' AND t.teacher_name = '张金宝';
