INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '团委的武迪老师，一周看电影，一周讲电影，从视听元素，情节，主题等分析导演风格，选择的电影多为外国的奥斯卡影片，质量不错，就是签到高频，几乎每节课都签到，三次直接取消成绩，病假事假也不除外，只要够三次就取消成绩', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '电影导演分析' AND t.teacher_name = '武迪';
