INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '对于想学习电影构图剪辑之类可以选', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '电影美学-拉片课' AND t.teacher_name = '陈朝钧';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '我自己很推荐，因为我喜欢电影而且对电影术语技术比较感兴趣，这门课的主题就是电影拉片，即“一格一格地看电影，深度解读电影”。感觉跟语文阅读理解很像，但解读对象是电影的视听语言。有两三次随堂小测，记得都是现场解读老师播放的电影片段。主要看的是《辛德勒的名单》，也解读了很多别的电影片段。给分好像是挺客观的，我上课喜欢回答问题，所以最后是A，也有些同学吐槽老师给分不高。建议喜欢电影、想更了解电影术语、想要更能看懂镜头语言选', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '电影美学-拉片课' AND t.teacher_name = '陈朝昀';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 5, '不喜欢电影拉票很折磨，但是喜欢就可以来，电影拉票就是慢放电影，分析镜头场景音乐等的用意，类似语文阅读理解', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '电影美学-拉片课' AND t.teacher_name = '陈老师';
