INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '老师人超赞，性格很温柔，就算是知道有学生没来也从来不签到，而且作业很少，不强制完成，最后结课虽然说是考试，但实际上只是把作业交了就可以了，老师人真的炒炒鸡好', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '法社会学' AND t.teacher_name = '王晨';
