INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '教得挺慢的，会讲因素 数字和基本对话，会有文化艺术方面的拓展，老师人挺不错的，有想学的可以告诉她都会讲，时间上也很体谅我们请假比较方便', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '法语口语入门' AND t.teacher_name = '张瑾';
