INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师上课很认真，能听懂并且跟上节奏，老师很负责，讲解细致，就是作业有点多', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高等数学' AND t.teacher_name = '朱圣芝';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师上课很认真负责也能听懂跟上节奏，就是作业偏多', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高等数学' AND t.teacher_name = '朱圣芝';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 3, '这节课可能有点难，认真去听的话还是会有很大的收获的，可以为将来的数学竞赛做准备，最后的考核就是提交一篇数学论文不查重，但是一定要听课哦，老师人很好', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高等数学方法' AND t.teacher_name = '何卫力';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '主要是讲解数学题的，为了大学生数学竞赛做准备，课上老师很有激情，偶尔也会讲一些你感觉真的很棒的经验、思考、认识等等，这个老师把数学和生活、文学都联系了起来，而且讲题讲的方法也很易懂，对于想备考数学竞赛的同学来说，超赞的！', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高等数学方法' AND t.teacher_name = '邵吉光';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '学期结束完成一份商业计划书', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高端国际人才' AND t.teacher_name = '任苒';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 2, 3, 3, 3, '老师很负责，能对上每个同学和名字，所以不要想着逃课，课上可以学到很多东西，人很好，作业基本上一周一次，有小组作业和个人作业，需要pre,最后结课要展示和交英语版的商业计划书(就是平时作业的汇总），考试不难，可以找到原题', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高端国际人才' AND t.teacher_name = '王小娟';
