INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师讲得很好，也很幽默，认真听能学到很多，平时课下基本没有作业，最后会有一个创业计划书，但是都是在课上完成过的内容,不是很麻烦', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高端国际人才英语' AND t.teacher_name = '任苒';
