INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '丁老师篮球课教的很好，是退役的国家级裁判，想提高篮球水平尤其是全场水平的尤其推荐', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高级篮球' AND t.teacher_name = '丁健';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '丁健老师是退役的国家级裁判，水平很高。想提升篮球水平，特别是全场篮球水平的尤其推荐。但是课上训练强度不小，量力而行', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高级篮球' AND t.teacher_name = '丁健';
