INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '老师主要讲的课本包括高级综合英语以及视听说教程。除此之外，冯老师还会拓展一些语言相关的知识。老师上课有时候让我们上台演讲或者小组合作表演。师资方面，目前我们有一个老师和两位助教，都挺负责的，在群里问问题，老师们很快就会回。上课体验还挺好的，如果有人上课干些别的事情，只要不影响别人，老师一般不会管。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高级综合英语' AND t.teacher_name = '冯蕾';
