INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '上课基本都是书上的内容，但是期间会讲很多故事，老师在国外待过挺久，上课也停幽默的，你上课只要别在他眼皮子底下肆无忌惮玩游戏其他基本没事，不怎么管你，也没有作业，很轻松的，平时分高度契合期中考试，给分比较规矩。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高级综合英语' AND t.teacher_name = '王云彤';
