INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '周志杰老师说话很好听，不严，但是扣分，该扣也得扣，迟到或者少做作业，都不会留情，作业留的很少，可以迟交，课前不检查，课后交，只要在期末前全部交齐，课间会放歌曲或电影，不占课间，这段时间疾病多发，请病假可以直接找老师在群里发，没有病历证明也可以，不会算旷课', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高级综合英语' AND t.teacher_name = '周志杰';
