INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '推荐', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高清人文电影鉴赏与研究' AND t.teacher_name = '何腾';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 5, 3, '主要是看电影，在五教阶梯教室上课，环境比较不好，冬冷夏热。上课不点名，看完电影会点人起来回答问题。有结课论文，2500字以上，手写，不查重，可以直接chat或者上网复制，但是会查有没有用手写模拟器，这个就看负责的课代表查不查', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高清人文电影赏析与研究' AND t.teacher_name = '何腾';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '在阶梯教室看电影，老师找的资源都很高清，体验很好', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高清人文电影欣赏' AND t.teacher_name = '何腾';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '每两周放一部电影，老师会叫中间坐着的同学依次回答电影的观后感。无论回答成什么样，老师都会给予鼓励。只要差不多在结课前一个月去，加微信群和听结课论文要求，两周内交一篇2800字的手写社科类论文，基本在知网搜电影再合成一下就行，但不能是ai代写，一经发现就是作弊，和本人都不会商量直接报告给教学科。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '高清人文电影与研究' AND t.teacher_name = '何腾';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 3, '上课内容就是老师会先简单介绍一下然后就是放歌剧。老师偶尔会抽一部分人点名。考核是1500字的结课论文，据说还有一个非常简单的小笔试，这种任选课给分应该都不会低。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '歌剧欣赏' AND t.teacher_name = '韩娉婷';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '上课老师讲解介绍歌剧、音乐剧的历史和相关知识，多数时间都在放映歌剧高清录像。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '歌剧欣赏' AND t.teacher_name = '赵亚宁';
