INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 2, 3, '土建学院必修课，课堂内容以介绍工程可持续发展为主要内容，老师课上废话很少，节奏比较慢，但上课开始时会提问上节课内容，当做点名，答不出来没有关系他不扣分，最后一点，他很喜欢上课提问英汉互译', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '工程可持续发展' AND t.teacher_name = '解会兵';
