INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师这门课主要讲的是文言文，但是文章是繁体字不是简体字，讲各种古代经典，诸子百家的思想，诗经等，平时会要求读论语，孟子等，老师讲的很详细，超好。老师还会发红包，给学生带小零食等，基本不点名', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '古代汉语入门' AND t.teacher_name = '刘竹林';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '一点都水不了，上课干货满满，课后会安排读书任务，需要读书笔记之类的东西，闭卷考试，卷面达不到60不加平时分的', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '古代汉语入门' AND t.teacher_name = '刘竹林';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 5, '就是上课读读文言文，都是很有意思的故事，也比较简单 平时作业就是读书，轮到自己就发一下读书心得，考试闭卷，内容简单', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '古代汉语入门' AND t.teacher_name = '刘竹林老师';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '老师会讲古典小说发展、超多古典小说以及她的理解，打铃下课一秒不拖，上课内容讲课风格有趣，但是会点名，有两次开卷考试，没有作业。签到正常，写卷子有态度，给了A-。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '古典小说鉴赏' AND t.teacher_name = '宋颖';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '老师人很好，五一前还给我们免了一次课，放大家出去玩，上课老师也不强求听讲，让大家感兴趣就听一听，不感兴趣做自己的事情就好；期中会有一次读书报告，平时写过一两次赏析作业', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '古诗词鉴赏' AND t.teacher_name = '鲁竹';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '每节课都会听一些古典音乐，老师人超好，也很有很多校内校外演出活动的门票，想看的可以联系她，老师不考勤，认真写完论文结课作业成绩就很高', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '关英馨' AND t.teacher_name = '名曲欣赏';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '邢颖老师的课，非常好。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '管理会计' AND t.teacher_name = '邢颖';
