INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 5, 3, '很轻松，跳一会休息很长一会，儿童节还送了我们礼物，热的天还会送我们到阴凉地上课', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '花样跳绳' AND t.teacher_name = '刘傲磊';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '讲一些跟环境有关的热点问题，要写3000-5000字的论文，而且在课上答辩，有点困难。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '环境科学前沿' AND t.teacher_name = '于晓华';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师上课超级清晰，但是很严格，每一次实验做完都要亲自找她检查，不过也减轻了期末复习的压力，只要认真听课期末肯定高分。讲课讲的很好没话说，但是很难摸鱼', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '汇编' AND t.teacher_name = '诸强';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '刘铭老师对实验的要求超级高，会检查每一个实验，如果平时实验不做作业不交到一定程度真的会取消考试资格，查实验的时候给人压力蛮大的，但非常客观，如果你完成了所有任务，即使当时老师的评价不高，期末平时分也会非常非常非常好（基本给满），建议想学到东西的人选', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '汇编与接口技术' AND t.teacher_name = '刘铭';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '老师给分很高，学完每一章都有作业，作业在练习教材中，有答案直接抄就行', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '会计学原理' AND t.teacher_name = '李远慧';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 2, '本课为限选课，老师上课不点名，一共七个小作业，每周完成，一个作业占期末10分，最后期末大作业30分，构成全部100分。上课做什么老师都不会管，一学期下来没人固定一次pre，很轻松，不占分', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '会计学原理' AND t.teacher_name = '任远';
