INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '神中神。每节课先拿出10-20分钟回顾上节课讲了啥。ppt都是罗老师自己做的。经常拓展知识（主要是最优化方法）且点到为止。助教批改作业很用心。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '几何与代数（B）' AND t.teacher_name = '罗自炎';
