INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '英语课，没有作业和pre，整个学期只有一个小组作业是拍视频', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '唐学华';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '选', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '唐学华';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '老师非常好', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '唐学华';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '老师人很好，上课依照教材讲授与文化有关的知识，老师会讲很多案例，内容丰富，上课较轻松，但是不容易水，每节扫码签到，请假不用假条，活动较多', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '王云彤';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '会讲分析、认识其他文化的理论', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '王云彤';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '老师会结合自身经历讲，比较有意思，也容易懂', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '王云彤';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 3, '这门课的话能学到很多关于中外文化的知识，老师很温柔，讲的很详细，当时专门给一节课让我们看一场关于跨文化交际冲突的电影，上课的话比较轻松，基本上老师一个人讲的比较多，有时候会拖堂，有时候会雨课堂提问，纸质版的作业很少很少几乎没有，基本上都是像pre(自愿，多做可以加分)和海报制作和展示(小组为单位)这种任务，而且老师人真的超级好，会给你提供很多英语学习方面的资源和平台。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '王云彤';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '老师上课很认真，最好别摸鱼，会要求同学们积极回答问题，', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '张海燕';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '虽然很多人说张海燕老师的课任务很多避雷，但是我觉得她是一个很认真负责的老师，是想真的教会我们知识锻炼能力，她不会挨着点名但会每节课抽一些同学回顾上节课知识，她把给分的细则说得很明确，所以如果认真上她的课就不用怕给分低，而且老师人其实很好的', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '张海燕';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 5, '首先，选张海燕老师的课的前提是真想来学点东西。想选门课开摆的话一定不要选张海燕老师的。其次，老师的要求会稍微严格一点，可能是课程的原因，老师会要求她在群里发的信息有feedback，平时上课也要有互动。如果你是上课积极的类型，不仅得分高，大概率还能跟老师的关系不错。最后，考核的各种作业比较多，但除了两篇作文之外，都很有意思，时间上也不会紧张，准备时间还蛮充分的，但是你要是那种喜欢把ddl堆在一起做的类型的话那么可能会有点紧张。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '张海燕';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '课程主要是不同文化之间的差异，内容很丰富，志杰老师上课互动很强，一般有问题回一个一个问，点名次数较少', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '跨文化交际' AND t.teacher_name = '周志杰';
