INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 5, 3, '介绍领导力以及沟通力的培养方法，都是干货，老师讲的很有意思', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '领导力与沟通力' AND t.teacher_name = '刘东平';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '介绍领导力和沟通力的培养方法，都是干货，老师讲的很有意思', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '领导力与沟通力' AND t.teacher_name = '刘东平';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 2, 3, 1, 2, '上课讲的还好，但是分给的不高，两次平常作业，一次案例分析，都看的挺重的，总得来说不推荐', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '伦理与企业社会责任' AND t.teacher_name = '吕希艳';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '外教上课基本就是跟大家互动而已，虽然是全英文授课，但是上课时会很放松，因为老师几乎都是寓教于乐，课堂氛围很放松。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '伦理与社会责任' AND t.teacher_name = '外教';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '老师会结合PPT内容和当下实事进行教学，有时会播放视频，不是单纯的讲概念而是慢慢引导你去理解，老师每节课会用雨课堂签到，有时还会点名，每节课都有回答问题环节和小组讨论(可能第一节课没有)，想要得高分的话就要保证每次的考勤，期中期末的作业完成的差不多然后课上多回答问题就可以了', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '伦理与社会责任' AND t.teacher_name = '张楠';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '比较水的一门课，一学分，工程素养类，听不听老师不太管，只要点名都到了期末论文交了基本都是A', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '漫谈现代信息社会热点' AND t.teacher_name = '裴丽、郑晶晶';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 3, '这个课程上半个学期，每节课一个信息社会的主题，有一些教学视频，上课轻松，可摸鱼，可认真听讲，最后交一篇论文就好了，word四五页左右。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '漫谈信息社会热点' AND t.teacher_name = '裴丽';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '绘画，写生，创意', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '美育' AND t.teacher_name = '唐然，杨梦婉';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 3, '教学资料和课程作业比较古老（约10年前），但是作业非常简单', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '面向对象程序设计与C++' AND t.teacher_name = '翟高寿';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '瞿老师yyds，都给我选！平时完全不考勤，去不去全凭自觉。但是老师讲得超级好看哇，如果你本身有一定基础的话完全可以当拔高课来听，没有基础的话自己下去努努力还是能跟得上的。而且平时完全没有作业，一节授课，一节上机，基本上机课就能把作业写完（一道题），这年头谁家老师作业只留一道题啊我丢。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '面向对象程序设计与c++' AND t.teacher_name = '瞿有利';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 1, 3, 1, 2, '老师讲的云里雾里，根本不懂还觉得自己很牛逼，结课设计巨难，教了1加1让做微积分', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '面向对象的程序开发（Java）' AND t.teacher_name = '徐鹏';
