INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 2, 3, 3, 2, '课程很难，张老师讲课语速很快，喜欢点名，马老师语速很慢，不点名，两个极端', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '模拟与数字电子技术' AND t.teacher_name = '张秀敏，马韬';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 2, 3, 2, 2, '避雷，前八周的模电部分是张秀敏讲的，我的评价是纯纯副作用，自己看书效果好一万倍，偏偏上课还很严，低会头都能给点起来', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '模拟与数字电子技术' AND t.teacher_name = '张秀敏，马韬';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 3, '这节课是两节连上，适合去上课写写作业什么的，而且每个人上课只会被点一次名签到，其他时候不会签到，结课是以论文的形式或者你上课回答问题如果说的比较好可以免去写论文直接得A。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '纳米技术' AND t.teacher_name = '富鸣';
