INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '老师特好，考试很多次机会，只要你平时认真跟老师学了，基本不可能过不了。因为哪怕你第一次没过还可以找老师考n多次，直到你过为止。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '男子排球' AND t.teacher_name = '唱钊赫';
