INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '对正手反手基本动作及步伐进行讲解，最后会有双打表演赛。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '乒乓球初级' AND t.teacher_name = '陈健文';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '挺好的，建议有基础的报', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '乒乓球运动训练' AND t.teacher_name = '王利利';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 5, '作为美育课很好，老师温柔，会对你的作品大夸特夸！喜欢美术设计的可以来。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '平面与空间几何设计方法' AND t.teacher_name = '陈岚';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 1, 3, 1, 1, '老师课上要做一堆没用的东西，她也不交，每一个都要上传打卡，花很多时间，下课后每一次课后都有一堆作业，除了课上作业，课后作业，期末还有小组设计和个人设计 要做实物和汇报和做图，重点，每一次都特别认真做了，期末还被表扬了，分数特别低', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '平面与空间形式创新设计方法' AND t.teacher_name = '陈岚';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '每节课就是看看电影，看完老师可能会找几个人问一下看完的感受，期末作业写一个3000字观后感，电影挺有意思的，氛围也很好', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '葡萄牙语电影赏析' AND t.teacher_name = '谢珊娜';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 2, '点名频率非常高 给分平平', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '葡萄牙语影片赏析' AND t.teacher_name = '祝明姗';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '上课氛围很好，老师经常进行小组讨论，需要一定英语水平但要求不会很高，课堂上包容性挺强，最后的结课论文是案例分析（我那次是课上讨论过的案例），给分很好，上课发言积极的话给分更高', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '企业伦理与社会责任' AND t.teacher_name = 'Christian Kahl';
