INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '上课练习期末考试的内容，后期有时间也可以在课上打比赛，专项满分比较好拿，可以反复测试（至少王虹老师的课是这样的）', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '气排球' AND t.teacher_name = '王虹';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '体育课在东校区体育馆，老师很好，课堂也很轻松，最后很多人都是满分', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '气排球' AND t.teacher_name = '王虹';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 2, '老师会教三大项以及一些其他动作，但是老师也不是专门练这个的，教学水平就会比较差（没我好哈哈哈）。想选这个课的要对健身感兴趣，得自己去健身房练，不然不好过的。好好练都能拿a。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '器械健美' AND t.teacher_name = '陈骥';
