INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '老师讲一些关于生物方面的知识 有时会放b站视频 身为水课毫不占用课后时间，上课老师偶尔会提问 被点了也会重复再问一遍问题 给分很好 老师也很随性强推！', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '生命科学纵横' AND t.teacher_name = '付远辉';
