INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 2, 3, 2, 2, '学习一些没用的生物知识，师资正常，上课体验就是摸鱼', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '生命科学纵横' AND t.teacher_name = '纪丰民';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 5, 2, '课程本身很无聊，算是高中生物的一点小延伸还加上社会主义核心价值观（不用怀疑，就是在生物课程上讲zz），但这课相当水，你总是去就能得A，我之前请了2次假（请假就是在群里说一声），按实际情况填到结课作业里了，后面也得了A', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '生命科学纵横' AND t.teacher_name = '纪丰民';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 2, '这个课据说每个老师讲的东西都不一样，这个老师讲的是生物学，基因细胞之类的，我高中没学生物听不懂，估计学过的也听不懂，（老师偶尔会讲讲物理数学估计这才是他的真爱）会点人回答问题，一节课可能有一两次吧，好在大家都回答不出来，老师也不会难为人，一共留三次论文，都是科普类，全校公选，反正都大差不差', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '生命科学纵横' AND t.teacher_name = '纪丰民';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 5, 2, '差不多算高中生物的延伸吧，纪丰民老师人挺好的，上课会叫人回答问题，后半学期好像因为上半学期去的人太少了就开始点名了，但是给分很高', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '生命科学纵横' AND t.teacher_name = '纪丰民';
