INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师人超好，讲的好，还会发以前的网课视频，上课不听听网课视频也行，还会给往年卷子带着做，老师超好！', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '数据结构与算法' AND t.teacher_name = '李向前';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 2, '老师的讲课比较平淡（个人看法），比较偏向于读课件。但课程平台上会有老师录的视频，很适合用来期末复习，而且考核上机作业也比较水，大家可以放心选', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '数据结构与算法' AND t.teacher_name = '李向前';
