INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '如果报名参加操场集体舞可以免乐跑免考核', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '体育舞蹈' AND t.teacher_name = '周艳茹';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 3, '讲述铁路遗产相关信息，也会组织去铁路博物馆参观（免费）。偶尔上课会让写几道关于铁路的知识交上去当作签到。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '铁路建筑遗产保护与开发' AND t.teacher_name = '胡映东，夏海山';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 2, '上课就是按照PPT顺序，不用课本，也不按课本内容进行，期末考试基本就是PPT和往年题的内容，考试不是很难，但是上课讲的比较深澳比较难。但是有一个很可怕的点，这个老师超级凶，脾气很差，总是骂人，他的要求很高，课堂上很少能达到他的要求，几乎每节课都会训人。当然也挺负责的，如果表现很好达到他的要求他也不会为难人。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '通信电子线路' AND t.teacher_name = '章嘉懿';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '看一节电影，讲一节课电影分析，电影很好看，期中写了一篇小论文，期末题和上课内容有关，但是老师给分挺好的', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '外国电影观摩与欣赏' AND t.teacher_name = '陈朝昀';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师上课基本上带大家玩和表演有关的游戏(用英语)，后小半节课教大家表演，是E人的天堂，老师超级开明温柔，鼓励大家多交朋友，去谈恋爱', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '外国戏剧表演与实践' AND t.teacher_name = '章睿君';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 3, '学发球，对打，对打实在不行可以看动作，夏天有点晒，户外球场有点累', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '网球' AND t.teacher_name = '留森华';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '西操网球场上课，比较轻松', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '网球' AND t.teacher_name = '王金连';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师教的很好，会一对一指导，小白也能拿高分', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '网球初级课' AND t.teacher_name = '张汉锋';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 5, '老师教的很好，很具体，小白上手快。就是需要一个比较合拍的搭档。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '网球基础课' AND t.teacher_name = '张汉峰';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '选纳米材料的必修。开卷考试，只能看他的PPT复印件，我当年打印了很久。老师性格比较严厉。作业不是很难，就是他下节课提问的问题，但需要查资料。请假可以，但不能因为物理实验请假，老师不会深究你的请假原因。千万不要不去，就算不去，一定要提前请假。考试内容不会超出PPT的内容，上课可以摸鱼，但还是要听一听，不然找起来太麻烦，毕竟ppt有好多页,建议同志们提前打印，可能需要半个小时打印。我个人觉得还挺有意思，考试比较顺利，得了A。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '危险化学品' AND t.teacher_name = '程志明';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 4, 3, '邓老师人很好，讲课比较仔细，而且有问题问的话她也会细心解答，平常分直接给满', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '微积分' AND t.teacher_name = '邓小琴';
