INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '老师非常有耐心，考试只要做过两套题就能过，原题重复率很高', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '线性代数与空间解析几何' AND t.teacher_name = '范秉理';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 4, 5, '开卷考试非常简单，王波波会给每个人发一本自己编写的教材，完全就是抄作业的答案，结课考试的时候还送了每人一根糖葫芦', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '相对论入门' AND t.teacher_name = '王波波';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 5, 3, '课程有点硬核，但老师人很好，好几节课都给我们带吃的。平时作业按时交，期末考试就是平时作业题，还开卷，把老师发群里的平时作业的答案打印下来带过去嘎嘎抄，按照上面做必A', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '相对论入门' AND t.teacher_name = '王波波';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 2, 3, '张驰老师人挺好的，但是给分确实一般。主要进行课外志愿活动。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '心理素质培养与训练' AND t.teacher_name = '张驰';
