INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 3, 3, '老师要求比较严，每次上课点名，一学期无论什么原因只能请假三次否则取消考试成绩，两种操的考核也比较严格，但是老师人比较温柔也很漂亮，好好上课问题不大', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '艺术体操' AND t.teacher_name = '董依晨';
