INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 1, 3, 2, 1, '还以为是容嬷嬷在上课呢，听不懂在说什么，差生文具多，各种奇葩要求，比如上课不能关窗（上过课的懂得都懂）。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '中级财务会计' AND t.teacher_name = '于国红';
