INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 3, 2, '老师很严格不温柔，缺勤3次直接不及格，上课会写东西交上去，会提问，给分不高，上课可以干别的', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '中外旅游景点赏析' AND t.teacher_name = '余青';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 2, 3, 1, 2, '老师感觉对多媒体不太认识的样子 每节课都要找同学给她播放视频和调整ppt 一半的课上都会让写字数很多的小作业 期末按时按规交了结课论文 不明白为什么给了B 避雷啊避雷', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '中外旅游景点赏析' AND t.teacher_name = '余青';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 3, 3, 2, 2, '上课体验一般，平时跟一些学生关系不错', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '中文写作' AND t.teacher_name = '杜英歌';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 4, 3, 5, 3, '这个是心理委员中级课程，每节课都是大家围在一起，每节课刚开始做一些游戏，然后进行一些理论的教授，然后下半节课会进行助人的模拟演练，一个同学当助人者也就是心理委员之类的角色，一个人当受助者提供问题向助人者求助，大概五分钟左右，接着老师会进行点评，最后大家再总结交流一下。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '助人理论与技能训练' AND t.teacher_name = '田宝伟';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '上课具体内容就是关灯看音乐剧，课堂轻松愉快', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '走进音乐剧' AND t.teacher_name = '韩娉婷';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '韩老师专业素养充足，并且很容易通融。上课时间基本用来看音乐剧，老师会穿插做一些讲解，对音乐剧感兴趣但尚未入门的同学推荐选这门课。课上不提问。一学期的签到次数≤3次。最后一次课提交小论文并进行闭卷考试，其中考试试题均出自课上讲过的内容。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '走进音乐剧' AND t.teacher_name = '韩娉婷';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '特别好，上课带着看音乐剧，考核卷子也很简单', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '走进音乐剧' AND t.teacher_name = '韩娉婷';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 5, 5, '上课基本就是老师放音乐剧给你看的，去不去都行，但是一般来说会有一次很重要的点名，直接决定你期末论文是手写还是电子版哦', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '走进音乐剧' AND t.teacher_name = '韩娉婷';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '上课就是在学活关上灯欣赏音乐剧，这学期老师点名几率可高，老师说对代课签到行为零容忍！', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '走进音乐剧' AND t.teacher_name = '韩娉婷';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '能一起踢比赛认识了很多朋友', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '足球' AND t.teacher_name = '赵田力';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 5, 3, 4, 5, '能踢比赛认识了很多朋友', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '足球' AND t.teacher_name = '赵田力';
INSERT INTO review (student_id, course_instance_id, course_id, teacher_id, overall_score, grading_score, teaching_score, workload_score, content, study_tips, exam_type, like_count, status, create_time) SELECT 1, ci.id, cb.id, t.id, 2, 3, 3, 3, '课程有一定难度，但认真听老师讲能听懂。如果不想听上课也不点名，可以不去。期末分占50%，平时成绩由作业和一个论文构成。作业几乎每节课都会留，而且找不到答案，有点难。论文也有些麻烦，但平时分比例这么高也挺好的。', '', '', 0, 'PUBLISHED', NOW() FROM course_base cb JOIN course_instance ci ON ci.course_base_id = cb.id JOIN teacher t ON ci.teacher_id = t.id WHERE cb.course_name = '最优化方法' AND t.teacher_name = '罗自炎';
